import { useMemo, useState, useEffect, useRef, useCallback } from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import { useMarket } from "@/lib/MarketContext";
import { useCompare } from "@/lib/useFavorites";
import { useWatchlists } from "@/lib/useFavorites";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { fmt } from "@/lib/parseItem";
import { Skeleton } from "@/components/ui/skeleton";
import { Reveal } from "@/components/landing/motion";
import {
  Search, Star, Scale, ArrowUpRight, History, RotateCcw,
  X, Frown,
} from "lucide-react";

const HISTORY_KEY = "castia.lookupHistory";
const HISTORY_MAX = 10;

function readHistory() {
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
}

function writeHistory(entry) {
  try {
    const arr = readHistory().filter((h) => h !== entry);
    const next = [entry, ...arr].slice(0, HISTORY_MAX);
    localStorage.setItem(HISTORY_KEY, JSON.stringify(next));
  } catch { /* ignore */ }
}

function clearHistory() {
  try { localStorage.removeItem(HISTORY_KEY); } catch { /* ignore */ }
}

function ResultCard({ item, isStarred, onToggleStar, onCompare }) {
  return (
    <Reveal>
      <div className="bg-white/[0.02] border border-white/10 rounded-2xl p-6">
        <div className="flex flex-col md:flex-row gap-6">
          <div className="w-full md:w-48 h-48 bg-gradient-to-br from-emerald-500/10 to-emerald-500/5 rounded-xl border border-emerald-500/10 flex items-center justify-center shrink-0">
            <span className="text-4xl font-heading font-black text-emerald-400/30">
              {item.name?.charAt(0) || "?"}
            </span>
          </div>
          <div className="flex-1 min-w-0">
            <div className="flex items-start justify-between gap-4">
              <div>
                <h2 className="font-heading text-2xl font-black tracking-tight">{item.name}</h2>
                <div className="flex items-center gap-2 mt-1">
                  {item.tier > 0 && (
                    <span className="text-[10px] font-mono uppercase tracking-wider text-amber-400 bg-amber-500/10 border border-amber-500/20 px-2 py-0.5 rounded-full">
                      T{item.tier}
                    </span>
                  )}
                  <span className="text-[10px] font-mono uppercase tracking-wider text-zinc-500">{item.category}</span>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-5">
              <div>
                <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Median Price</div>
                <div className="text-lg font-heading font-bold text-emerald-400 tabular-nums">{fmt(item.median)}</div>
              </div>
              <div>
                <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Samples</div>
                <div className="text-lg font-heading font-bold tabular-nums">{item.samples}</div>
              </div>
              <div>
                <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">IQR Range</div>
                <div className="text-lg font-heading font-bold tabular-nums text-zinc-300">
                  {fmt(item.iqrLow)} – {fmt(item.iqrHigh)}
                </div>
              </div>
              <div>
                <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Confidence</div>
                <div className={`text-lg font-heading font-bold tabular-nums ${
                  item.confidence === "high" ? "text-emerald-400" : item.confidence === "medium" ? "text-amber-400" : "text-zinc-400"
                }`}>
                  {item.confidence}
                </div>
              </div>
            </div>

            <div className="flex items-center gap-3 mt-6 flex-wrap">
              <button
                onClick={onToggleStar}
                className={`inline-flex items-center gap-2 font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors ${
                  isStarred
                    ? "bg-amber-500/20 text-amber-400 border border-amber-500/30"
                    : "bg-white/[0.04] text-white border border-white/10 hover:border-amber-500/40"
                }`}
              >
                <Star className={`w-3.5 h-3.5 ${isStarred ? "fill-amber-400" : ""}`} />
                {isStarred ? "Favorited" : "Add to Favorites"}
              </button>
              <button
                onClick={onCompare}
                className="inline-flex items-center gap-2 border border-white/10 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
              >
                <Scale className="w-3.5 h-3.5" /> Compare
              </button>
              <Link
                to={`/item/${item.key}`}
                className="inline-flex items-center gap-2 border border-white/10 hover:border-white/30 text-zinc-300 hover:text-white font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
              >
                Full details <ArrowUpRight className="w-3.5 h-3.5" />
              </Link>
            </div>
          </div>
        </div>
      </div>
    </Reveal>
  );
}

export default function LookupPage() {
  const { market } = useMarket();
  const [q, setQ] = useState("");
  const [searching, setSearching] = useState(false);
  const [showHistory, setShowHistory] = useState(true);
  const inputRef = useRef(null);
  const watchlists = useWatchlists();
  const compare = useCompare();

  const lookupHistory = useMemo(() => showHistory ? readHistory() : [], [showHistory]);

  useEffect(() => {
    if (inputRef.current) inputRef.current.focus();
  }, []);

  const isHash = /^#?[a-zA-Z0-9]{4,}$/.test(q.trim());
  const query = q.trim().toLowerCase();
  const queryIsHash = isHash && query.replace(/^#/, "");

  const results = useMemo(() => {
    if (!market?.rowsByKey || !query) return [];
    const items = Array.from(market.rowsByKey.values());
    if (queryIsHash) {
      const hash = queryIsHash;
      return items.filter((item) => item.key?.toLowerCase().includes(hash)).slice(0, 20);
    }
    return items.filter((item) => item.name?.toLowerCase().includes(query)).slice(0, 20);
  }, [market, query, queryIsHash]);

  useEffect(() => {
    if (query) {
      const timer = setTimeout(() => setSearching(false), 200);
      return () => clearTimeout(timer);
    }
    setSearching(false);
  }, [query, results]);

  const selectedItem = results.length === 1 ? results[0] : null;

  const handleSelect = useCallback((itemKey) => {
    writeHistory(itemKey);
    setShowHistory(false);
  }, []);

  const handleToggleStar = useCallback((key) => {
    watchlists.toggle(key);
  }, [watchlists]);

  const handleCompare = useCallback((key) => {
    compare.add(key);
  }, [compare]);

  const isHashFormat = /^#?[a-zA-Z0-9]{4,12}$/.test(q.trim());
  const showValidationError = q.trim().length > 0 && !isHashFormat && !query.match(/^[a-zA-Z0-9 ]+$/);

  return (
    <div className="min-h-screen bg-bg-base text-white flex flex-col">
      <Header />
      <main className="flex-1 pt-32 pb-24">
        <div className="max-w-3xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal className="text-center md:text-left">
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">/ Lookup</div>
            <h1 className="font-heading text-5xl lg:text-6xl tracking-tighter font-black leading-[0.95] mb-4">
              Item <span className="text-emerald-400">Lookup</span>
            </h1>
            <p className="text-zinc-400 max-w-xl mb-8 text-lg">
              Search for items by name or paste a Castia item hash to see its details.
            </p>
          </Reveal>

          <Reveal delay={0.05}>
            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-zinc-500 pointer-events-none" />
              <input
                ref={inputRef}
                type="text"
                value={q}
                onChange={(e) => { setQ(e.target.value); setSearching(true); setShowHistory(false); }}
                onKeyDown={(e) => {
                  if (e.key === "Escape") { setQ(""); inputRef.current?.blur(); }
                  if (e.key === "Enter" && results.length > 0) {
                    handleSelect(results[0].key);
                  }
                }}
                placeholder="Search items or paste a hash (e.g. #abc123)..."
                className="w-full bg-white/[0.04] border border-white/10 rounded-xl pl-12 pr-12 py-4 text-base text-white placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 transition-all font-mono"
              />
              {q && (
                <button
                  onClick={() => { setQ(""); inputRef.current?.focus(); }}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-white transition-colors"
                  aria-label="Clear search"
                >
                  <X className="w-4 h-4" />
                </button>
              )}
            </div>
            {showValidationError && (
              <p className="text-amber-400 text-xs mt-2 font-mono">
                Invalid hash format. Expected something like <code className="text-zinc-400">#a1b2c3</code>.
              </p>
            )}
          </Reveal>

          {/* Recent lookups */}
          {!q && lookupHistory.length > 0 && (
            <Reveal delay={0.1} className="mt-8">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2 text-xs text-zinc-500 font-mono uppercase tracking-wider">
                  <History className="w-3.5 h-3.5" /> Recent lookups
                </div>
                <button
                  onClick={() => { clearHistory(); setShowHistory(true); }}
                  className="text-[10px] text-zinc-600 hover:text-zinc-400 transition-colors uppercase tracking-wider font-mono"
                >
                  Clear
                </button>
              </div>
              <div className="flex flex-wrap gap-2">
                {lookupHistory.map((key) => {
                  const row = market?.rowsByKey?.get(key);
                  return (
                    <button
                      key={key}
                      onClick={() => { setQ(key); handleSelect(key); }}
                      className="inline-flex items-center gap-2 bg-white/[0.04] border border-white/10 hover:border-emerald-500/30 rounded-full px-3 py-1.5 text-xs text-zinc-300 hover:text-white transition-colors"
                    >
                      {row?.name || key}
                    </button>
                  );
                })}
              </div>
            </Reveal>
          )}

          {/* Searching indicator */}
          {searching && query && results.length === 0 && (
            <div className="mt-8 space-y-4">
              <div className="bg-white/[0.02] border border-white/10 rounded-2xl p-6">
                <div className="flex flex-col md:flex-row gap-6">
                  <Skeleton className="w-full md:w-48 h-48 rounded-xl" />
                  <div className="flex-1 space-y-4">
                    <Skeleton className="h-6 w-48" />
                    <Skeleton className="h-4 w-24" />
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-5">
                      {Array.from({ length: 4 }).map((_, i) => (
                        <div key={i} className="space-y-2">
                          <Skeleton className="h-3 w-16" />
                          <Skeleton className="h-6 w-20" />
                        </div>
                      ))}
                    </div>
                    <div className="flex gap-3 mt-6">
                      <Skeleton className="h-9 w-36 rounded-sm" />
                      <Skeleton className="h-9 w-28 rounded-sm" />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* No results */}
          {!searching && query && results.length === 0 && (
            <Reveal delay={0.1}>
              <div className="mt-16 text-center max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-zinc-500/10 border border-zinc-500/30 mb-6">
                  <Frown className="w-7 h-7 text-zinc-400" />
                </div>
                <h2 className="font-heading text-2xl font-black mb-3">Item not found</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-6">
                  No item matches <strong className="text-white">{q}</strong>. Check the spelling or try a different term.
                </p>
                <button
                  onClick={() => { setQ(""); inputRef.current?.focus(); }}
                  className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3 rounded-sm transition-colors"
                >
                  <RotateCcw className="w-4 h-4" /> Search again
                </button>
              </div>
            </Reveal>
          )}

          {/* Result list (multiple matches) */}
          {!searching && results.length > 1 && (
            <Reveal delay={0.1} className="mt-8">
              <div className="text-xs text-zinc-500 mb-3 font-mono">{results.length} result{results.length === 1 ? "" : "s"} matching "{q}"</div>
              <div className="divide-y divide-white/10 border border-white/10 rounded-2xl overflow-hidden">
                {results.map((item, i) => {
                  const isStarred = watchlists.has(item.key);
                  return (
                    <motion.button
                      key={item.key}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: i * 0.02 }}
                      onClick={() => handleSelect(item.key)}
                      className="w-full text-left p-4 hover:bg-white/[0.03] transition-colors flex items-center justify-between group"
                    >
                      <div className="flex-1 min-w-0">
                        <div className="font-heading font-bold text-white group-hover:text-emerald-400 transition-colors">{item.name}</div>
                        <div className="flex items-center gap-2 mt-0.5">
                          {item.tier > 0 && <span className="text-[10px] text-amber-400/70 font-mono">T{item.tier}</span>}
                          <span className="text-xs text-zinc-500">{item.category}</span>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 shrink-0">
                        <span className="font-mono tabular text-emerald-400 font-bold text-sm">{fmt(item.median)}</span>
                        <div className="flex items-center gap-1">
                          <button
                            onClick={(e) => { e.stopPropagation(); handleToggleStar(item.key); }}
                            className={`p-1.5 rounded-sm transition-colors ${isStarred ? "text-amber-400" : "text-zinc-600 hover:text-amber-400"}`}
                            aria-label={isStarred ? "Remove from favorites" : "Add to favorites"}
                          >
                            <Star className={`w-4 h-4 ${isStarred ? "fill-amber-400" : ""}`} />
                          </button>
                          <button
                            onClick={(e) => { e.stopPropagation(); handleCompare(item.key); }}
                            className="p-1.5 rounded-sm text-zinc-600 hover:text-emerald-400 transition-colors"
                            aria-label="Add to compare"
                          >
                            <Scale className="w-4 h-4" />
                          </button>
                        </div>
                        <ArrowUpRight className="w-4 h-4 text-zinc-600 group-hover:text-emerald-400 transition-colors" />
                      </div>
                    </motion.button>
                  );
                })}
              </div>
            </Reveal>
          )}

          {/* Empty initial state */}
          {!query && lookupHistory.length === 0 && (
            <Reveal delay={0.15} className="mt-16 text-center">
              <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-emerald-500/10 border border-emerald-500/30 mb-6">
                <Search className="w-7 h-7 text-emerald-400" />
              </div>
              <p className="text-zinc-500 text-sm">
                Paste a Castia item hash or type a name to search.
              </p>
            </Reveal>
          )}

          {/* Single result detail card */}
          {!searching && selectedItem && (
            <div className="mt-8">
              <ResultCard
                item={selectedItem}
                isStarred={watchlists.has(selectedItem.key)}
                onToggleStar={() => handleToggleStar(selectedItem.key)}
                onCompare={() => handleCompare(selectedItem.key)}
              />
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}
